import{_ as a,o as t,c as n,ag as s}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq/index.md","filePath":"faq/index.md"}'),r={name:"faq/index.md"};function o(i,e,l,d,c,h){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><p><strong>Does Diamond Analytics work for both baseball and softball?</strong> Yes. When you create a team you select Baseball or Softball. The app adjusts field diagrams, pitch types, mechanics assessments, and analytics thresholds automatically. A single subscription covers teams of both sports.</p><p><strong>Can I use Diamond Analytics without a paid subscription?</strong> Free accounts can create a team, add players, and enter data using all loggers. Analytics, training plans, report cards, and lineup builders require a paid subscription. This lets you build up a season of data before subscribing.</p><p><strong>Can multiple people log data at the same time?</strong> Yes. All team members with Scorekeeper role or higher can log data simultaneously. Changes are synced in real time.</p><p><strong>How do I switch between teams?</strong> Use the team selector in the app header or on the dashboard. The active team controls which roster, analytics, and settings are shown throughout the app.</p><h2 id="data-entry" tabindex="-1">Data Entry <a class="header-anchor" href="#data-entry" aria-label="Permalink to &quot;Data Entry&quot;">​</a></h2><p><strong>What happens if I make a mistake logging data?</strong> Records can be freely edited or deleted within 2 hours of entry. After 2 hours a correction reason is required and the edit is logged for transparency. Head coaches can correct any record at any time.</p><p><strong>Can I log data from video after a game?</strong> Yes. Start a game session and select <strong>Unscored Past Games</strong> — any scheduled game without stats appears here. Log stats normally from video.</p><p><strong>Does voice logging work in Spanish?</strong> Spanish language support is coming soon.</p><h2 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h2><p><strong>Why is my ERA showing ERA (6-inn) or ERA (7-inn)?</strong> Diamond Analytics uses age-appropriate innings for ERA calculation. 8U–12U teams use 6-inning ERA and 13U and above use 7-inning ERA. See <a href="/analytics/era-explained.html">Understanding ERA</a> for details.</p><p><strong>How much data do I need before analytics are meaningful?</strong> As a general guide — batting average after 20+ at-bats, ERA after 10+ innings, fielding percentage after 20+ chances, mechanics after 5+ sessions.</p><p><strong>Can parents see their child&#39;s analytics?</strong> Yes. Parent role accounts have read access to all team analytics. Players can see their own stats highlighted in team leaderboards.</p><h2 id="subscriptions" tabindex="-1">Subscriptions <a class="header-anchor" href="#subscriptions" aria-label="Permalink to &quot;Subscriptions&quot;">​</a></h2><p><strong>Can I change my plan?</strong> Yes. Go to Settings → Manage Subscription to upgrade, downgrade, or cancel through the Stripe Customer Portal. Changes take effect at the next billing period.</p><p><strong>What happens when my free trial ends?</strong> You retain access to data entry. Analytics, training plans, report cards, and lineup builders are paused until you subscribe. Your data is never deleted.</p><p><strong>Can I get a refund?</strong> Contact support at support@diamondanalytics.app within 7 days of a charge for refund consideration.</p><h2 id="technical" tabindex="-1">Technical <a class="header-anchor" href="#technical" aria-label="Permalink to &quot;Technical&quot;">​</a></h2><p><strong>Does Diamond Analytics work offline?</strong> The app loads from cache when offline. Data entry requires an internet connection to save. Analytics load from cache if previously viewed.</p><p><strong>Which browsers are supported?</strong> Chrome and Safari are fully supported. Firefox has limited voice logging support. Edge works correctly.</p><p><strong>Voice logging does not work on my device — what should I do?</strong> Voice logging requires Chrome on Android or Safari on iOS. On Android, setting Google Voice Typing as your default keyboard improves reliability. See <a href="/voice-logging/mobile.html">Mobile Voice Logging</a> for setup instructions.</p>',22)])])}const u=a(r,[["render",o]]);export{g as __pageData,u as default};
